142→        match bindings {
143→            Ok(b) => {
144→                let out_path = PathBuf::from(env::var("OUT_DIR").unwrap());
145→                b.write_to_file(out_path.join("bindings.rs"))
146→                    .expect("Couldn't write bindings!");
147→            }
148→            Err(e) => {
149→                println!("cargo:warning=Unable to generate bindings: {}", e);
150→                println!("cargo:warning=Using bundled bindings.rs, which may be out of date");
151→                // copy src/bindings.rs to OUT_DIR
152→                std::fs::copy("src/bindings.rs", out.join("bindings.rs"))
153→                    .expect("Unable to copy bindings.rs");
154→            }
155→        }
156→    };
157→
158→    // stop if we're on docs.rs
159→    if env::var("DOCS_RS").is_ok() {
160→        return;
161→    }
162→
163→    let mut config = Config::new(&whisper_root);
