179→
180→    if cfg!(feature = "coreml") {
181→        config.define("WHISPER_COREML", "ON");
182→        config.define("WHISPER_COREML_ALLOW_FALLBACK", "1");
183→    }
184→
185→    if cfg!(feature = "cuda") {
186→        config.define("GGML_CUDA", "ON");
187→        config.define("CMAKE_POSITION_INDEPENDENT_CODE", "ON");
188→        config.define("CMAKE_CUDA_FLAGS", "-Xcompiler=-fPIC");
189→    }
190→
191→    if cfg!(feature = "hipblas") {
192→        config.define("GGML_HIP", "ON");
193→        config.define("CMAKE_C_COMPILER", "hipcc");
194→        config.define("CMAKE_CXX_COMPILER", "hipcc");
195→        println!("cargo:rerun-if-env-changed=AMDGPU_TARGETS");
